// libs/@app/data/src/offline-queue.ts
export function useMutationWithQueue() {
  const isOnline = useNetworkStatus();

  return useMutation({
    mutationFn: async (data) => {
      if (!isOnline) {
        // Queue for later
        await queueMutation(data);
        return data;
      }

      // Execute immediately
      return await executeRemote(data);
    },
  });
}
